#!/bin/bash

set -e

SHIM=$(dirname $0)/../Sources/_WippleSources.shim.swift

cat <<EOF > $SHIM
// This file is automatically generated; don't edit it!
internal let wippleSources = [
EOF

for file in $(dirname $0)/*.wpl; do
    cat <<EOF >> $SHIM
"$(basename $file)": #"""
$(cat $file)
"""#,

EOF
done

truncate -s-1 $SHIM
echo "]" >> $SHIM
